def get_script(status_key: str, **kwargs) -> str:
    """
    Retrieve and format a response script by status key.
    """
    template = SCRIPTS_MAP.get(status_key, SCRIPTS_MAP["FALLBACK"])
    try:
        return template.format(**kwargs)
    except KeyError:
        return template
